import React, { useState, useEffect } from "react";
import { useParams, Link } from "react-router-dom";
import { recipeAPI } from "../utils/api";
import "./Recipes.css";

const Recipes = () => {
  const { category } = useParams();
  const [recipes, setRecipes] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [filters, setFilters] = useState({
    category: category || "",
    cuisine: "",
    difficulty: "",
    search: "",
  });

  useEffect(() => {
    fetchRecipes();
  }, [filters, category]);

  const fetchRecipes = async () => {
    setLoading(true);
    setError(null);
    try {
      const params = {};
      Object.keys(filters).forEach((key) => {
        if (filters[key]) params[key] = filters[key];
      });

      console.log("Fetching recipes with params:", params);
      const response = await recipeAPI.getAll(params);
      console.log("Recipes API response:", response.data);

      // Handle different response structures
      let recipesData = [];
      if (response.data.recipes) {
        recipesData = response.data.recipes;
      } else if (response.data.data) {
        recipesData = response.data.data;
      } else if (Array.isArray(response.data)) {
        recipesData = response.data;
      }

      setRecipes(recipesData);
    } catch (error) {
      console.error("Error fetching recipes:", error);
      setError(
        "Failed to load recipes. Please check if the backend server is running."
      );
    } finally {
      setLoading(false);
    }
  };

  const handleFilterChange = (key, value) => {
    setFilters((prev) => ({ ...prev, [key]: value }));
  };

  if (loading) {
    return <div className="loading">Loading recipes...</div>;
  }

  if (error) {
    return <div className="error">{error}</div>;
  }

  return (
    <div className="recipes-page">
      <div className="container">
        <div className="recipes-header">
          <h1>
            {category
              ? `${
                  category.charAt(0).toUpperCase() + category.slice(1)
                } Recipes`
              : "All Recipes"}
          </h1>
          <Link to="/add-recipe" className="add-recipe-btn">
            Add New Recipe
          </Link>
        </div>

        <div className="filters">
          <input
            type="text"
            placeholder="Search recipes..."
            value={filters.search}
            onChange={(e) => handleFilterChange("search", e.target.value)}
            className="search-input"
          />
          <select
            value={filters.category}
            onChange={(e) => handleFilterChange("category", e.target.value)}
          >
            <option value="">All Categories</option>
            <option value="indian">Indian</option>
            <option value="chinese">Chinese</option>
            <option value="italian">Italian</option>
            <option value="mexican">Mexican</option>
            <option value="thai">Thai</option>
            <option value="american">American</option>
            <option value="mediterranean">Mediterranean</option>
            <option value="japanese">Japanese</option>
            <option value="french">French</option>
            <option value="other">Other</option>
          </select>
          <select
            value={filters.difficulty}
            onChange={(e) => handleFilterChange("difficulty", e.target.value)}
          >
            <option value="">Any Difficulty</option>
            <option value="easy">Easy</option>
            <option value="medium">Medium</option>
            <option value="hard">Hard</option>
          </select>
        </div>

        <div className="recipes-grid">
          {Array.isArray(recipes) && recipes.length > 0 ? (
            recipes.map((recipe) => (
              <div key={recipe._id} className="recipe-card">
                <div className="recipe-image">
                  <img
                    src={
                      recipe.image
                        ? `http://localhost:5000/uploads/${recipe.image}`
                        : "https://via.placeholder.com/300x200/667eea/ffffff?text=No+Image"
                    }
                    alt={recipe.title}
                    onError={(e) => {
                      e.target.src =
                        "https://via.placeholder.com/300x200/667eea/ffffff?text=No+Image";
                    }}
                  />
                  <div className="recipe-overlay">
                    <span className="category-tag">{recipe.category}</span>
                  </div>
                </div>
                <div className="recipe-info">
                  <h3>{recipe.title}</h3>
                  <p className="recipe-category">{recipe.category}</p>
                  <p className="recipe-cuisine">{recipe.cuisine}</p>
                  <p className="recipe-description">
                    {recipe.description.substring(0, 100)}...
                  </p>
                  <div className="recipe-meta">
                    <span>⏱️ {recipe.prepTime + recipe.cookTime} mins</span>
                    <span>👥 {recipe.servings} servings</span>
                    <span className={`difficulty ${recipe.difficulty}`}>
                      {recipe.difficulty}
                    </span>
                  </div>
                  <div className="recipe-actions">
                    <Link
                      to={`/recipes/${recipe._id}`}
                      className="btn btn-primary"
                    >
                      View Recipe
                    </Link>
                  </div>
                </div>
              </div>
            ))
          ) : (
            <div className="no-recipes">
              <p>
                No recipes found. Try adjusting your filters or add a new
                recipe!
              </p>
              <Link to="/add-recipe" className="btn btn-primary">
                Add New Recipe
              </Link>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Recipes;
